\begin{aligned}
S(y) &= \text{the number of supported facts} \\
N(y) &= \text{the number of not-supported facts} \\
\text{Prec}(y) &= \frac{S(y)}{S(y) + N(y)},\quad R_K(y) = \min\big(\frac{S(y)}{K}, 1\big) \\
F_1 @ K &= \begin{cases}
\frac{2\text{Prec}(y)R_K(y)}{Prec(y) + R_K(y)} & \text{if } S(y) > 0 \\
0, & \text{if } S(y) = 0
\end{cases} 
\end{aligned}
